create extension if not exists pgcrypto;
create extension if not exists citext;
create extension if not exists btree_gist;
create extension if not exists pg_trgm;

do $$
begin
  if not exists (select 1 from pg_type where typname = 'profile_status') then
    create type profile_status as enum ('ACTIVE', 'INACTIVE', 'LOCKED');
  end if;
  if not exists (select 1 from pg_type where typname = 'student_status') then
    create type student_status as enum ('ACTIVE', 'SUSPENDED', 'GRADUATED', 'DROPPED');
  end if;
  if not exists (select 1 from pg_type where typname = 'offering_status') then
    create type offering_status as enum ('DRAFT', 'OPEN', 'CLOSED', 'FINISHED', 'CANCELLED');
  end if;
  if not exists (select 1 from pg_type where typname = 'enrollment_status') then
    create type enrollment_status as enum ('ENROLLED', 'DROPPED', 'COMPLETED');
  end if;
  if not exists (select 1 from pg_type where typname = 'grade_status') then
    create type grade_status as enum ('DRAFT', 'SUBMITTED', 'APPROVED', 'LOCKED');
  end if;
  if not exists (select 1 from pg_type where typname = 'regrade_status') then
    create type regrade_status as enum ('PENDING', 'UNDER_REVIEW', 'RESOLVED', 'REJECTED', 'CANCELLED');
  end if;
end $$;

-- Base schema definitions must exist before functions, triggers, and RLS policies
-- that reference these relations.
create table if not exists public.roles (
  code text primary key,
  name text not null,
  description text
);

insert into public.roles (code, name, description)
values
  ('ADMIN', 'Administrator', 'Full access to manage the system'),
  ('LECTURER', 'Lecturer', 'Can manage grades and teaching workload'),
  ('STUDENT', 'Student', 'Can manage personal study activities')
on conflict (code) do nothing;

create table if not exists public.profiles (
  id uuid primary key references auth.users (id) on delete cascade,
  email citext not null unique,
  full_name text not null,
  role_code text not null references public.roles (code),
  status profile_status not null default 'ACTIVE',
  phone text,
  avatar_url text,
  must_change_password boolean not null default true,
  metadata jsonb not null default '{}'::jsonb,
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.departments (
  id uuid primary key default gen_random_uuid(),
  code text not null unique,
  name text not null,
  description text,
  is_active boolean not null default true,
  created_by uuid references public.profiles (id),
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.majors (
  id uuid primary key default gen_random_uuid(),
  department_id uuid not null references public.departments (id) on delete restrict,
  code text not null unique,
  name text not null,
  degree_level text not null default 'UNDERGRADUATE',
  is_active boolean not null default true,
  created_by uuid references public.profiles (id),
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.academic_classes (
  id uuid primary key default gen_random_uuid(),
  major_id uuid not null references public.majors (id) on delete restrict,
  code text not null unique,
  name text not null,
  cohort_year integer not null check (cohort_year >= 2000),
  is_active boolean not null default true,
  created_by uuid references public.profiles (id),
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.semesters (
  id uuid primary key default gen_random_uuid(),
  code text not null unique,
  name text not null,
  academic_year text not null,
  start_date date not null,
  end_date date not null,
  enrollment_start timestamptz not null,
  enrollment_end timestamptz not null,
  regrade_open_at timestamptz,
  regrade_close_at timestamptz,
  max_credits integer not null default 21 check (max_credits > 0),
  is_current boolean not null default false,
  created_by uuid references public.profiles (id),
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  constraint semesters_date_check check (start_date <= end_date),
  constraint semesters_enrollment_window_check check (enrollment_start < enrollment_end),
  constraint semesters_regrade_window_check check (
    regrade_open_at is null
    or regrade_close_at is null
    or regrade_open_at < regrade_close_at
  )
);

create table if not exists public.courses (
