  course_id uuid not null references public.courses (id) on delete cascade,
  prerequisite_course_id uuid not null references public.courses (id) on delete restrict,
  minimum_score numeric(4, 2) not null default 5.00 check (minimum_score >= 0 and minimum_score <= 10),
  created_at timestamptz not null default timezone('utc', now()),
  primary key (course_id, prerequisite_course_id),
  constraint course_prerequisites_self_check check (course_id <> prerequisite_course_id)
);

