  current_status student_status not null default 'ACTIVE',
  gender text,
  date_of_birth date,
  address text,
  emergency_contact text,
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now())
);

create table if not exists public.course_offerings (
  id uuid primary key default gen_random_uuid(),
  course_id uuid not null references public.courses (id) on delete restrict,
  semester_id uuid not null references public.semesters (id) on delete restrict,
  section_code text not null,
  title text,
  max_capacity integer not null check (max_capacity > 0),
  enrolled_count integer not null default 0 check (enrolled_count >= 0),
  registration_open_at timestamptz not null,
  registration_close_at timestamptz not null,
  attendance_weight numeric(5, 2) not null default 10.00 check (attendance_weight >= 0 and attendance_weight <= 100),
  midterm_weight numeric(5, 2) not null default 30.00 check (midterm_weight >= 0 and midterm_weight <= 100),
  final_weight numeric(5, 2) not null default 60.00 check (final_weight >= 0 and final_weight <= 100),
  passing_score numeric(4, 2) not null default 5.00 check (passing_score >= 0 and passing_score <= 10),
  status offering_status not null default 'DRAFT',
  notes text,
  created_by uuid references public.profiles (id),
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  constraint course_offerings_registration_window_check check (registration_open_at < registration_close_at),
  constraint course_offerings_weight_sum_check check (
    attendance_weight + midterm_weight + final_weight = 100.00
  ),
  constraint course_offerings_unique_section unique (semester_id, course_id, section_code)
);

create table if not exists public.teaching_assignments (
  id uuid primary key default gen_random_uuid(),
  course_offering_id uuid not null references public.course_offerings (id) on delete cascade,
  lecturer_id uuid not null references public.lecturers (id) on delete cascade,
  assignment_role text not null default 'PRIMARY',
  is_primary boolean not null default false,
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  unique (course_offering_id, lecturer_id)
);

create table if not exists public.schedules (
  id uuid primary key default gen_random_uuid(),
  course_offering_id uuid not null references public.course_offerings (id) on delete cascade,
  room_id uuid references public.rooms (id) on delete set null,
  day_of_week smallint not null check (day_of_week between 1 and 7),
  start_time time not null,
  end_time time not null,
  week_pattern text not null default 'ALL',
  start_date date,
  end_date date,
  note text,
  time_range int4range generated always as (
    int4range(
      (extract(hour from start_time)::int * 60) + extract(minute from start_time)::int,
      (extract(hour from end_time)::int * 60) + extract(minute from end_time)::int,
      '[)'
    )
  ) stored,
  is_demo boolean not null default false,
  demo_batch text,
  created_at timestamptz not null default timezone('utc', now()),
  updated_at timestamptz not null default timezone('utc', now()),
  constraint schedules_time_check check (start_time < end_time),
  constraint schedules_date_check check (start_date is null or end_date is null or start_date <= end_date)
);

