create or replace function public.set_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at := timezone('utc', now());
  return new;
end;
$$;

create or replace function public.current_user_role()
returns text
language sql
stable
security definer
set search_path = public
as $$
  select p.role_code
  from public.profiles p
  where p.id = auth.uid()
    and p.status = 'ACTIVE'
  limit 1;
$$;

create or replace function public.is_admin()
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select coalesce(public.current_user_role() = 'ADMIN', false);
$$;

create or replace function public.is_lecturer_assigned(p_offering_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select exists (
    select 1
    from public.teaching_assignments ta
    where ta.course_offering_id = p_offering_id
      and ta.lecturer_id = auth.uid()
  );
$$;

create or replace function public.score_to_letter(p_score numeric)
returns text
language plpgsql
immutable
as $$
begin
  if p_score is null then
    return null;
  elsif p_score >= 8.5 then
    return 'A';
  elsif p_score >= 8.0 then
    return 'B+';
  elsif p_score >= 7.0 then
    return 'B';
  elsif p_score >= 6.5 then
    return 'C+';
  elsif p_score >= 5.5 then
    return 'C';
  elsif p_score >= 5.0 then
    return 'D+';
  elsif p_score >= 4.0 then
    return 'D';
  else
    return 'F';
  end if;
end;
$$;

create or replace function public.score_to_gpa(p_score numeric)
returns numeric
language plpgsql
immutable
as $$
begin
  if p_score is null then
    return null;
  elsif p_score >= 8.5 then
    return 4.0;
  elsif p_score >= 8.0 then
    return 3.5;
  elsif p_score >= 7.0 then
    return 3.0;
  elsif p_score >= 6.5 then
    return 2.5;
  elsif p_score >= 5.5 then
    return 2.0;
  elsif p_score >= 5.0 then
    return 1.5;
  elsif p_score >= 4.0 then
    return 1.0;
  else
    return 0.0;
  end if;
end;
$$;

create or replace function public.recompute_grade_derived_fields()
returns trigger
language plpgsql
set search_path = public
as $$
declare
  v_weights record;
  v_total numeric;
begin
  select
    co.attendance_weight,
    co.midterm_weight,
    co.final_weight
  into v_weights
  from public.enrollments e
  join public.course_offerings co on co.id = e.course_offering_id
  where e.id = new.enrollment_id;

  if new.attendance_score is not null
     and new.midterm_score is not null
     and new.final_score is not null then
    v_total := round(
      (
        (new.attendance_score * v_weights.attendance_weight) +
        (new.midterm_score * v_weights.midterm_weight) +
        (new.final_score * v_weights.final_weight)
      ) / 100.0,
      2
    );

    new.total_score := v_total;
    new.letter_grade := public.score_to_letter(v_total);
    new.gpa_value := public.score_to_gpa(v_total);
  else
    new.total_score := null;
    new.letter_grade := null;
    new.gpa_value := null;
  end if;

  return new;
end;
$$;

create or replace function public.apply_grade_status_transition()
returns trigger
language plpgsql
set search_path = public
as $$
declare
  v_role text := public.current_user_role();
  v_actor_id uuid := auth.uid();
begin
  if tg_op <> 'UPDATE' then
    return new;
  end if;

  if v_actor_id is null then
    raise exception 'Authentication required';
  end if;

  if v_role is null then
    raise exception 'Active profile with role is required';
  end if;

  if old.status = 'LOCKED' and v_role <> 'ADMIN' then
    raise exception 'Locked grades can only be changed by admin';
  end if;

  if old.status <> 'DRAFT'
     and (
       new.attendance_score is distinct from old.attendance_score
       or new.midterm_score is distinct from old.midterm_score
       or new.final_score is distinct from old.final_score
     )
  then
    raise exception 'Scores can only be edited while grade status is DRAFT';
  end if;

  if new.status is not distinct from old.status then
    return new;
  end if;

  if old.status = 'DRAFT' and new.status = 'SUBMITTED' then
    if v_role not in ('LECTURER', 'ADMIN') then
      raise exception 'Only lecturer or admin can submit grades';
    end if;
    if new.attendance_score is null or new.midterm_score is null or new.final_score is null then
      raise exception 'Cannot submit grade with incomplete component scores';
    end if;
    new.submitted_at := timezone('utc', now());
    new.submitted_by := v_actor_id;
  elsif old.status = 'SUBMITTED' and new.status = 'APPROVED' then
    if v_role <> 'ADMIN' then
      raise exception 'Only admin can approve grades';
    end if;
    new.approved_at := timezone('utc', now());
    new.approved_by := v_actor_id;
  elsif old.status = 'SUBMITTED' and new.status = 'DRAFT' then
    if v_role <> 'ADMIN' then
      raise exception 'Only admin can return submitted grades to draft';
    end if;
  elsif old.status = 'APPROVED' and new.status = 'LOCKED' then
    if v_role <> 'ADMIN' then
      raise exception 'Only admin can lock grades';
    end if;
    new.locked_at := timezone('utc', now());
    new.locked_by := v_actor_id;
  elsif old.status = 'APPROVED' and new.status = 'DRAFT' then
    if v_role <> 'ADMIN' then
      raise exception 'Only admin can move approved grades to draft';
    end if;
    new.approved_at := null;
    new.approved_by := null;
    new.locked_at := null;
    new.locked_by := null;
  elsif old.status = 'LOCKED' and new.status = 'APPROVED' then
    if v_role <> 'ADMIN' then
      raise exception 'Only admin can unlock grades';
    end if;
    new.locked_at := null;
    new.locked_by := null;
  else
    raise exception 'Unsupported grade status transition: % -> %', old.status, new.status;
  end if;

  return new;
end;
$$;

create or replace function public.log_grade_change()
returns trigger
language plpgsql
set search_path = public
as $$
begin
  if row_to_json(old) is distinct from row_to_json(new) then
    insert into public.grade_change_logs (
      grade_id,
      changed_by,
      change_type,
      old_payload,
      new_payload,
      is_demo,
      demo_batch
    )
    values (
      new.id,
      auth.uid(),
      case
        when new.status is distinct from old.status then 'STATUS_CHANGED'
        else 'SCORE_CHANGED'
      end,
      to_jsonb(old),
      to_jsonb(new),
      new.is_demo,
      new.demo_batch
    );
  end if;

  return new;
end;
$$;

create or replace function public.log_audit_event(
  p_action text,
  p_entity_type text,
  p_entity_id text default null,
  p_target_user_id uuid default null,
  p_metadata jsonb default '{}'::jsonb
)
returns bigint
language plpgsql
security definer
set search_path = public
as $$
declare
  v_log_id bigint;
  v_actor_id uuid := auth.uid();
  v_request_role text := coalesce(auth.role(), '');
  v_actor_role text;
  v_action text := upper(trim(coalesce(p_action, '')));
  v_entity_type text := lower(trim(coalesce(p_entity_type, '')));
  v_raw_metadata jsonb := coalesce(p_metadata, '{}'::jsonb);
  v_metadata jsonb := '{}'::jsonb;
  v_allowed_actions text[];
begin
  if v_actor_id is null and v_request_role = 'service_role' then
    begin
      v_actor_id := nullif(v_raw_metadata ->> '__actor_id', '')::uuid;
    exception
      when others then
        raise exception 'Invalid service actor id in audit metadata';
    end;
  end if;

  if v_actor_id is null then
    raise exception 'Authentication required for audit logging';
  end if;

  if v_request_role <> 'service_role' and (v_raw_metadata ? '__actor_id') then
    raise exception 'Reserved metadata key "__actor_id" is not allowed';
  end if;

  v_metadata := v_raw_metadata - '__actor_id';

  select p.role_code
  into v_actor_role
  from public.profiles p
  where p.id = v_actor_id
    and p.status = 'ACTIVE'
  limit 1;

  if v_actor_role is null then
    raise exception 'Active actor profile is required for audit logging';
  end if;

  if v_action = '' or v_action !~ '^[A-Z0-9_]{3,80}$' then
    raise exception 'Invalid audit action';
  end if;

  if v_entity_type not in (
    'academic_classes',
    'auth',
    'course_offerings',
    'courses',
    'departments',
    'enrollments',
    'grades',
    'lecturers',
    'majors',
    'profiles',
    'regrade_requests',
    'rooms',
    'schedules',
    'semesters',
    'students'
  ) then
    raise exception 'Invalid audit entity_type';
  end if;

  if pg_column_size(v_metadata) > 16384 then
    raise exception 'Audit metadata payload is too large';
  end if;

  if v_actor_role = 'STUDENT' then
    v_allowed_actions := array[
      'AUTH_LOGIN',
      'PASSWORD_RESET',
      'PROFILE_UPDATED',
      'ENROLLMENT_REGISTER_TRIGGERED',
      'ENROLLMENT_CANCEL_TRIGGERED',
      'ENROLLMENT_REGISTERED',
      'ENROLLMENT_DROPPED',
      'REGRADE_REQUEST_CREATED'
    ];
  elsif v_actor_role = 'LECTURER' then
    v_allowed_actions := array[
      'AUTH_LOGIN',
      'PASSWORD_RESET',
      'PROFILE_UPDATED',
      'GRADE_SAVED',
      'GRADE_SHEET_SUBMITTED',
      'REGRADE_REQUEST_RESOLVED'
    ];
  elsif v_actor_role = 'ADMIN' then
    v_allowed_actions := array[
      'ACADEMIC_CLASS_UPDATED',
      'ACADEMIC_CLASS_CREATED',
      'ACADEMIC_CLASS_ACTIVATED',
      'ACADEMIC_CLASS_DEACTIVATED',
      'AUTH_LOGIN',
      'PASSWORD_RESET',
      'COURSE_OFFERING_UPDATED',
      'COURSE_OFFERING_CREATED',
      'COURSE_OFFERING_DELETED',
      'COURSE_UPDATED',
      'COURSE_CREATED',
      'COURSE_DELETED',
      'DEPARTMENT_UPDATED',
      'DEPARTMENT_CREATED',
      'DEPARTMENT_DELETED',
      'ENROLLMENT_REGISTER_TRIGGERED',
      'ENROLLMENT_CANCEL_TRIGGERED',
      'ENROLLMENT_REGISTERED',
      'ENROLLMENT_DROPPED',
      'GRADE_STATUS_CHANGED',
      'GRADE_BATCH_STATUS_CHANGED',
      'GRADE_SAVED',
      'GRADE_SHEET_SUBMITTED',
      'LECTURER_UPDATED',
      'LECTURER_CREATED',
      'LECTURER_ACTIVATED',
      'LECTURER_DEACTIVATED',
      'MAJOR_UPDATED',
      'MAJOR_CREATED',
      'MAJOR_ACTIVATED',
      'MAJOR_DEACTIVATED',
      'PROFILE_UPDATED',
      'REGRADE_REQUEST_CREATED',
      'REGRADE_REQUEST_RESOLVED',
      'ROOM_UPDATED',
      'ROOM_CREATED',
      'ROOM_ACTIVATED',
      'ROOM_DEACTIVATED',
      'SCHEDULE_UPDATED',
      'SCHEDULE_CREATED',
      'SEMESTER_UPDATED',
      'SEMESTER_CREATED',
      'SEMESTER_DELETED',
      'STUDENT_UPDATED',
      'STUDENT_CREATED',
      'STUDENT_ACTIVATED',
      'STUDENT_DEACTIVATED',
      'USER_PROVISIONED',
      'USER_UPDATED'
    ];
  else
    raise exception 'Unsupported role for audit logging';
  end if;

  if not (v_action = any(v_allowed_actions)) then
    raise exception 'Audit action "%" is not allowed for role "%"', v_action, v_actor_role;
  end if;

  insert into public.audit_logs (
    actor_id,
    actor_role,
    action,
    entity_type,
    entity_id,
    target_user_id,
    metadata
  )
  values (
    v_actor_id,
    v_actor_role,
    v_action,
    v_entity_type,
    p_entity_id,
    p_target_user_id,
    v_metadata
  )
  returning id into v_log_id;

  return v_log_id;
end;
$$;

create or replace function public.register_enrollment(p_offering_id uuid)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_actor_id uuid := auth.uid();
  v_profile public.profiles;
  v_student public.students;
  v_offering record;
  v_existing_enrollment record;
  v_current_credits integer;
  v_missing_prerequisite text;
  v_conflict boolean;
  v_enrollment_id uuid;
begin
  if v_actor_id is null then
    raise exception 'Authentication required';
  end if;

  select * into v_profile
  from public.profiles
  where id = v_actor_id;

  if not found or v_profile.role_code <> 'STUDENT' then
    raise exception 'Only students can register for course offerings';
  end if;

  if v_profile.status <> 'ACTIVE' then
    raise exception 'Your account is not active';
  end if;

  select * into v_student
  from public.students
  where id = v_actor_id;

  if not found or v_student.current_status <> 'ACTIVE' then
    raise exception 'Your student profile is not active';
  end if;

  select
    co.*,
    s.max_credits as semester_max_credits,
    c.credit_hours as course_credit_hours
  into v_offering
  from public.course_offerings co
  join public.semesters s on s.id = co.semester_id
  join public.courses c on c.id = co.course_id
  where co.id = p_offering_id
  for update;

  if not found then
    raise exception 'Course offering not found';
  end if;

  if v_offering.status <> 'OPEN' then
    raise exception 'Course offering is not open for registration';
  end if;

  if timezone('utc', now()) < v_offering.registration_open_at
     or timezone('utc', now()) > v_offering.registration_close_at
  then
    raise exception 'Registration window is closed';
  end if;

  select e.id, e.status
  into v_existing_enrollment
  from public.enrollments e
  where e.student_id = v_actor_id
    and e.course_offering_id = p_offering_id
  for update;

  if v_existing_enrollment.id is not null
     and v_existing_enrollment.status <> 'DROPPED'
  then
    raise exception 'You are already registered for this course offering';
  end if;

  select c.code
  into v_missing_prerequisite
  from public.course_prerequisites cp
  join public.courses c on c.id = cp.prerequisite_course_id
  where cp.course_id = v_offering.course_id
    and not exists (
      select 1
      from public.grades g
      join public.enrollments e on e.id = g.enrollment_id
      join public.course_offerings previous_offering on previous_offering.id = e.course_offering_id
      where e.student_id = v_actor_id
        and previous_offering.course_id = cp.prerequisite_course_id
        and e.status <> 'DROPPED'
        and g.status in ('APPROVED', 'LOCKED')
        and coalesce(g.total_score, 0) >= cp.minimum_score
    )
  limit 1;

  if v_missing_prerequisite is not null then
    raise exception 'Missing prerequisite course: %', v_missing_prerequisite;
  end if;

  select exists (
    select 1
    from public.enrollments e
    join public.course_offerings current_offering on current_offering.id = e.course_offering_id
    join public.schedules existing_schedule on existing_schedule.course_offering_id = current_offering.id
    join public.schedules new_schedule on new_schedule.course_offering_id = p_offering_id
    where e.student_id = v_actor_id
      and e.status = 'ENROLLED'
      and current_offering.semester_id = v_offering.semester_id
      and existing_schedule.day_of_week = new_schedule.day_of_week
      and existing_schedule.time_range && new_schedule.time_range
  ) into v_conflict;

  if v_conflict then
    raise exception 'Schedule conflict detected';
  end if;

  select coalesce(sum(c.credit_hours), 0)
  into v_current_credits
  from public.enrollments e
  join public.course_offerings co on co.id = e.course_offering_id
  join public.courses c on c.id = co.course_id
  where e.student_id = v_actor_id
    and e.status = 'ENROLLED'
    and co.semester_id = v_offering.semester_id;

  if v_current_credits + v_offering.course_credit_hours > v_offering.semester_max_credits then
    raise exception 'Credit limit exceeded for this semester';
  end if;

  if v_offering.enrolled_count >= v_offering.max_capacity then
    raise exception 'Course offering is full';
  end if;

  if v_existing_enrollment.id is not null and v_existing_enrollment.status = 'DROPPED' then
    update public.enrollments
    set
      status = 'ENROLLED',
      enrolled_at = timezone('utc', now()),
      dropped_at = null,
      drop_reason = null,
      is_demo = v_offering.is_demo,
      demo_batch = v_offering.demo_batch
    where id = v_existing_enrollment.id
    returning id into v_enrollment_id;
  else
    insert into public.enrollments (
      student_id,
      course_offering_id,
      status,
      is_demo,
      demo_batch
    )
    values (
      v_actor_id,
      p_offering_id,
      'ENROLLED',
      v_offering.is_demo,
      v_offering.demo_batch
    )
    returning id into v_enrollment_id;
  end if;

  update public.course_offerings
  set enrolled_count = enrolled_count + 1
  where id = p_offering_id;

  perform public.log_audit_event(
    'ENROLLMENT_REGISTERED',
    'enrollments',
    v_enrollment_id::text,
    v_actor_id,
    jsonb_build_object(
      'course_offering_id', p_offering_id,
      'student_id', v_actor_id,
      'reactivated', (v_existing_enrollment.id is not null and v_existing_enrollment.status = 'DROPPED')
    )
  );

  return v_enrollment_id;
end;
$$;

create or replace function public.cancel_enrollment(
  p_enrollment_id uuid,
  p_reason text default null
)
returns boolean
language plpgsql
security definer
set search_path = public
as $$
declare
  v_actor_id uuid := auth.uid();
  v_role text := public.current_user_role();
  v_enrollment record;
begin
  if v_actor_id is null then
    raise exception 'Authentication required';
  end if;

  select
    e.*,
    co.registration_open_at,
    co.registration_close_at
  into v_enrollment
  from public.enrollments e
  join public.course_offerings co on co.id = e.course_offering_id
  where e.id = p_enrollment_id
  for update;

  if not found then
    raise exception 'Enrollment not found';
  end if;

  if v_enrollment.status <> 'ENROLLED' then
    raise exception 'Enrollment is already cancelled or completed';
  end if;

  if v_role = 'STUDENT' and v_enrollment.student_id <> v_actor_id then
    raise exception 'You can only cancel your own enrollment';
  end if;

  if v_role = 'STUDENT'
     and (
       timezone('utc', now()) < v_enrollment.registration_open_at
       or timezone('utc', now()) > v_enrollment.registration_close_at
     ) then
    raise exception 'Cancellation window is closed';
  end if;

  if v_role not in ('ADMIN', 'STUDENT') then
    raise exception 'You do not have permission to cancel enrollment';
  end if;

  update public.enrollments
  set
    status = 'DROPPED',
    dropped_at = timezone('utc', now()),
    drop_reason = p_reason
  where id = p_enrollment_id;

  update public.course_offerings
  set enrolled_count = greatest(enrolled_count - 1, 0)
  where id = v_enrollment.course_offering_id;

  perform public.log_audit_event(
    'ENROLLMENT_DROPPED',
    'enrollments',
    p_enrollment_id::text,
    v_enrollment.student_id,
    jsonb_build_object('reason', p_reason)
  );

  return true;
end;
$$;

create or replace function public.calculate_student_cumulative_gpa4(p_student_id uuid)
returns numeric
language sql
stable
set search_path = public
as $$
  select round(
    coalesce(
      sum(g.gpa_value * c.credit_hours) / nullif(sum(c.credit_hours), 0),
      0
    )::numeric,
    2
  )
  from public.grades g
  join public.enrollments e on e.id = g.enrollment_id
  join public.course_offerings co on co.id = e.course_offering_id
  join public.courses c on c.id = co.course_id
  where e.student_id = p_student_id
    and g.status in ('APPROVED', 'LOCKED')
    and e.status <> 'DROPPED';
$$;

create or replace function public.calculate_student_cumulative_score10(p_student_id uuid)
returns numeric
language sql
stable
set search_path = public
as $$
  select round(
    coalesce(
      sum(g.total_score * c.credit_hours) / nullif(sum(c.credit_hours), 0),
      0
    )::numeric,
    2
  )
  from public.grades g
  join public.enrollments e on e.id = g.enrollment_id
  join public.course_offerings co on co.id = e.course_offering_id
  join public.courses c on c.id = co.course_id
  where e.student_id = p_student_id
    and g.status in ('APPROVED', 'LOCKED')
    and e.status <> 'DROPPED';
$$;

drop view if exists public.report_student_distribution;
create view public.report_student_distribution
with (security_invoker = true)
as
select
  d.id as department_id,
  d.code as department_code,
  d.name as department_name,
  m.id as major_id,
  m.code as major_code,
  m.name as major_name,
  ac.id as academic_class_id,
  ac.code as academic_class_code,
  ac.name as academic_class_name,
  count(s.id)::int as total_students
from public.academic_classes ac
join public.majors m on m.id = ac.major_id
join public.departments d on d.id = m.department_id
left join public.students s on s.academic_class_id = ac.id and s.current_status <> 'DROPPED'
group by d.id, d.code, d.name, m.id, m.code, m.name, ac.id, ac.code, ac.name;

drop view if exists public.report_course_pass_rate;
create view public.report_course_pass_rate
with (security_invoker = true)
as
select
  c.id as course_id,
  c.code as course_code,
  c.name as course_name,
  count(g.id)::int as total_completed,
  count(*) filter (where coalesce(g.total_score, 0) >= co.passing_score)::int as total_passed,
  count(*) filter (where coalesce(g.total_score, 0) < co.passing_score)::int as total_failed,
  round(
    coalesce(
      (count(*) filter (where coalesce(g.total_score, 0) >= co.passing_score)::numeric
        / nullif(count(g.id), 0)::numeric) * 100,
      0
    ),
    2
  ) as pass_rate
from public.course_offerings co
join public.courses c on c.id = co.course_id
left join public.enrollments e on e.course_offering_id = co.id and e.status <> 'DROPPED'
left join public.grades g on g.enrollment_id = e.id and g.status in ('APPROVED', 'LOCKED')
group by c.id, c.code, c.name, co.passing_score;

drop view if exists public.report_class_gpa_average;
create view public.report_class_gpa_average
with (security_invoker = true)
as
select
  ac.id as academic_class_id,
  ac.code as class_code,
  ac.name as class_name,
  sem.id as semester_id,
  sem.name as semester_name,
  round(avg(g.gpa_value)::numeric, 2) as average_gpa4,
  round(avg(g.total_score)::numeric, 2) as average_score10
from public.students s
join public.academic_classes ac on ac.id = s.academic_class_id
join public.enrollments e on e.student_id = s.id and e.status <> 'DROPPED'
join public.grades g on g.enrollment_id = e.id and g.status in ('APPROVED', 'LOCKED')
join public.course_offerings co on co.id = e.course_offering_id
join public.semesters sem on sem.id = co.semester_id
group by ac.id, ac.code, ac.name, sem.id, sem.name;

drop view if exists public.report_academic_warnings;
create view public.report_academic_warnings
with (security_invoker = true)
as
select
  s.id as student_id,
  s.student_code,
  p.full_name as student_name,
  ac.code as class_code,
  coalesce(sum(c.credit_hours), 0)::int as completed_credits,
  public.calculate_student_cumulative_gpa4(s.id) as cumulative_gpa4,
  public.calculate_student_cumulative_score10(s.id) as cumulative_score10
from public.students s
join public.profiles p on p.id = s.id
join public.academic_classes ac on ac.id = s.academic_class_id
left join public.enrollments e on e.student_id = s.id and e.status <> 'DROPPED'
left join public.grades g on g.enrollment_id = e.id and g.status in ('APPROVED', 'LOCKED')
left join public.course_offerings co on co.id = e.course_offering_id
left join public.courses c on c.id = co.course_id
group by s.id, s.student_code, p.full_name, ac.code
having public.calculate_student_cumulative_gpa4(s.id) < 2.0;

