drop policy if exists regrade_requests_insert_student on public.regrade_requests;
create policy regrade_requests_insert_student
on public.regrade_requests
for insert
to authenticated
with check (
  student_id = auth.uid()
  and exists (
    select 1
    from public.grades g
    join public.enrollments e on e.id = g.enrollment_id
    join public.course_offerings co on co.id = e.course_offering_id
    join public.semesters s on s.id = co.semester_id
    where g.id = regrade_requests.grade_id
      and e.id = regrade_requests.enrollment_id
      and e.student_id = auth.uid()
      and g.status in ('APPROVED', 'LOCKED')
      and (
        s.regrade_open_at is null
        or s.regrade_close_at is null
        or timezone('utc', now()) between s.regrade_open_at and s.regrade_close_at
      )
  )
);

