-- Prevent self-service privilege escalation when updating profiles directly.
create or replace function public.protect_profile_self_update()
returns trigger
language plpgsql
set search_path = public
as $$
declare
  v_actor_id uuid := auth.uid();
  v_actor_role text := current_setting('request.jwt.claim.role', true);
begin
  if v_actor_id is null then
    if v_actor_role = 'service_role' or current_user in ('postgres', 'supabase_admin') then
      return new;
    end if;
    raise exception 'Authentication required';
  end if;

  if public.is_admin() then
    return new;
  end if;

  if new.id <> v_actor_id then
    raise exception 'You can only update your own profile';
  end if;

  if old.role_code is distinct from new.role_code
     or old.status is distinct from new.status
     or old.email is distinct from new.email
     or old.must_change_password is distinct from new.must_change_password
     or old.metadata is distinct from new.metadata
     or old.is_demo is distinct from new.is_demo
     or old.demo_batch is distinct from new.demo_batch
  then
    raise exception 'You are not allowed to update protected profile fields';
  end if;

  return new;
end;
$$;

drop trigger if exists profiles_protect_self_update on public.profiles;
create trigger profiles_protect_self_update
before update on public.profiles
for each row
execute function public.protect_profile_self_update();

drop policy if exists profiles_update_self_or_admin on public.profiles;
create policy profiles_update_self_or_admin
on public.profiles
for update
to authenticated
using (
  public.is_current_user_active()
  and (
    public.is_admin()
    or auth.uid() = id
  )
)
with check (
  public.is_current_user_active()
  and (
    public.is_admin()
    or auth.uid() = id
  )
);

