-- Grade status state machine + score mutation guard.

-- Regrade status lifecycle and required payload validations.
create or replace function public.apply_regrade_status_transition()
returns trigger
language plpgsql
set search_path = public
as $$
declare
  v_role text := public.current_user_role();
  v_actor_id uuid := auth.uid();
begin
  if tg_op <> 'UPDATE' then
    return new;
  end if;

  if v_actor_id is null then
    raise exception 'Authentication required';
  end if;

  if v_role not in ('ADMIN', 'LECTURER') then
    raise exception 'Only admin or lecturer can transition regrade status';
  end if;

  if new.status is not distinct from old.status then
    return new;
  end if;

  if old.status = 'PENDING' and new.status in ('UNDER_REVIEW', 'RESOLVED', 'REJECTED', 'CANCELLED') then
    null;
  elsif old.status = 'UNDER_REVIEW' and new.status in ('RESOLVED', 'REJECTED', 'CANCELLED') then
    null;
  else
    raise exception 'Unsupported regrade status transition: % -> %', old.status, new.status;
  end if;

  if new.status = 'RESOLVED' then
    if new.resolved_total_score is null then
      raise exception 'resolved_total_score is required when status is RESOLVED';
    end if;

    if new.resolved_total_score < 0 or new.resolved_total_score > 10 then
      raise exception 'resolved_total_score must be between 0 and 10';
    end if;

    if nullif(trim(coalesce(new.resolution_note, '')), '') is null then
      raise exception 'resolution_note is required when status is RESOLVED';
    end if;
  end if;

  new.reviewed_at := timezone('utc', now());
  new.reviewed_by := v_actor_id;

  return new;
end;
$$;

drop trigger if exists regrade_requests_apply_status_transition on public.regrade_requests;
create trigger regrade_requests_apply_status_transition
before update on public.regrade_requests
for each row
execute function public.apply_regrade_status_transition();

