-- One-command SQL helper to activate and promote an existing auth account to ADMIN.
create or replace function public.promote_profile_to_admin(
  p_email text,
  p_full_name text default null
)
returns uuid
language plpgsql
security definer
set search_path = public, auth
as $$
declare
  v_email text := lower(trim(coalesce(p_email, '')));
  v_full_name text := nullif(trim(coalesce(p_full_name, '')), '');
  v_user_id uuid;
begin
  if v_email = '' then
    raise exception 'Email is required';
  end if;

  select u.id
  into v_user_id
  from auth.users u
  where lower(u.email) = v_email
  limit 1;

  if v_user_id is null then
    raise exception 'No auth user found for email %', v_email;
  end if;

  if v_full_name is null then
    select nullif(trim(coalesce(u.raw_user_meta_data ->> 'full_name', '')), '')
    into v_full_name
    from auth.users u
    where u.id = v_user_id;
  end if;

  v_full_name := coalesce(v_full_name, 'System Admin');

  update auth.users
  set
    raw_app_meta_data = coalesce(raw_app_meta_data, '{}'::jsonb)
      || jsonb_build_object('role', 'ADMIN'),
    updated_at = timezone('utc', now())
  where id = v_user_id;

  insert into public.profiles (
    id,
    email,
    full_name,
    role_code,
    status,
    must_change_password,
    metadata
  )
  values (
    v_user_id,
    v_email,
    v_full_name,
    'ADMIN',
    'ACTIVE',
    false,
    jsonb_build_object('source', 'promote_profile_to_admin')
  )
  on conflict (id)
  do update set
    email = excluded.email,
    full_name = excluded.full_name,
    role_code = excluded.role_code,
    status = excluded.status,
    must_change_password = false,
    metadata = coalesce(public.profiles.metadata, '{}'::jsonb) || excluded.metadata,
    updated_at = timezone('utc', now());

  return v_user_id;
end;
$$;

revoke execute on function public.promote_profile_to_admin(text, text) from public;
revoke execute on function public.promote_profile_to_admin(text, text) from authenticated;
revoke execute on function public.promote_profile_to_admin(text, text) from anon;
grant execute on function public.promote_profile_to_admin(text, text) to service_role;

